import { plan, install } from 'hermesone';

// 1) Preview the exact release — show this to the user for approval.
const p = await plan();
console.log(`Would install ${p.asset} (${p.tag}), sha512 ${p.sha512 ? 'published' : 'MISSING'}`);

// 2) After the user approves, install. The package verifies sha512 before
//    installing (refuses if unverified); on macOS the signed app goes
//    straight into /Applications. Subscribe to progress if you want.
await install({ onProgress: (e) => console.log(e.phase) });
